import { Container, styled } from '@mui/material';
import { createRootRouteWithContext, Outlet } from '@tanstack/react-router';

import { useTheme } from '../AppThemeProvider';
import FileExplorer from '../components/FileExplorer';
import { ThemeSwitch } from '../components/ThemeSwitch';
import { fetchImageForSlug } from '../utils/fetchImage';
import { fetchMarkdown } from '../utils/fetchMarkdown';

const StyledNav = styled('nav', {
  name: 'nav',
})(({ theme }) => ({
  display: 'flex',
  flexDirection: 'column',
  paddingTop: theme.spacing(6),
  position: 'sticky',
  top: 0,
  height: '100vh',
  ['& .MuiSwitch-root']: {
    marginBottom: theme.spacing(2),
  },
}));

const RootRoute = () => {
  const { themeMode, toggleTheme } = useTheme();
  // const { mode, setMode } = useColorScheme();

  const handleChange = (_event: React.ChangeEvent<HTMLInputElement>) => {
    // localStorage.setItem('themeMode', event.target.checked ? 'light' : 'dark');
    toggleTheme();
    // setMode(event.target.checked ? 'light' : 'dark');
  };

  return (
    <Container sx={{ display: 'flex', flexDirection: 'row', gap: '0.5rem' }}>
      <StyledNav>
        <ThemeSwitch checked={themeMode === 'dark'} onChange={handleChange} inputProps={{ 'aria-label': 'Toggle Theme' }} />
        <FileExplorer />
      </StyledNav>
      <Outlet />
    </Container>
  );
};

export const Route = createRootRouteWithContext<{
  fetchMarkdown: typeof fetchMarkdown;
  fetchImage: typeof fetchImageForSlug;
}>()({
  component: () => <RootRoute />,
  notFoundComponent: () => <h1>oh no, 404 caught in __root</h1>,
});
