import { styled, SxProps, Theme, useTheme } from '@mui/material/styles';
import {
  BookIcon,
  BugIcon,
  CalendarIcon,
  CircleAlertIcon,
  CircleHelpIcon,
  FireExtinguisherIcon,
  GemIcon,
  HardHatIcon,
  InfoIcon,
  ListIcon,
  PencilIcon,
  QuoteIcon,
  RocketIcon,
  StarIcon,
  SwordsIcon,
  WandSparklesIcon,
} from 'lucide-react';
import React from 'react';

const StyledBlockquote = styled('blockquote', { name: 'div' })(({ theme }) => ({
  // marginTop: '2rem',
  // marginBottom: '2rem',
  display: 'flex',
  flexDirection: 'column',
  paddingLeft: '1rem',
  borderLeft: '0.5rem solid',
  borderColor: theme.palette.primary.main,
  fontStyle: 'italic',
  ['& span ']: {
    padding: 0,
    margin: 0,
  },
  ['p:empty']: {
    display: 'none',
  },
  ['& img']: {
    marginTop: '1rem',
    marginBottom: '1rem',
  },
}));

const StyledTitleRow = styled('span')({
  width: '100%',
  display: 'flex',
  justifyContent: 'flex-start',
  alignItems: 'center',
  svg: {
    marginRight: '1rem',
  },
  // ['& *.obsidian-embed']: {
  // margin: '1rem',
  // },
});

type CalloutProps = {
  children: React.ReactNode;
  title?: string;
  type: string;
};

const getIconForCallout = (type: string) => {
  switch (type.toLowerCase()) {
    case 'pencil':
    case 'tip':
      return <PencilIcon />;
    case 'gem':
      return <GemIcon />;
    case 'info':
      return <InfoIcon />;
    case 'rocket':
      return <RocketIcon />;
    case 'swords':
      return <SwordsIcon />;
    case 'question':
      return <CircleHelpIcon />;
    case 'warning':
      return <CircleAlertIcon />;
    case 'danger':
      return <FireExtinguisherIcon />;
    case 'bug':
      return <BugIcon />;
    case 'example':
      return <ListIcon />;
    case 'star':
      return <StarIcon />;
    case 'book':
      return <BookIcon />;
    case 'magic':
      return <WandSparklesIcon />;
    case 'calendar':
      return <CalendarIcon />;
    case 'wip':
      return <HardHatIcon />;
    default:
      return <QuoteIcon />;
  }
};

const getCalloutTextColor = (type: string, theme: Theme) => {
  return theme.palette.getContrastText(getBackgroundColorForCallout(type, theme));
};

const getBackgroundColorForCallout = (type: string, theme: Theme) => {
  switch (type) {
    case 'warning':
    case 'danger':
    case 'bug':
      return theme.palette.error.main;
    case 'magic':
    case 'calendar':
    case 'book':
    case 'info':
    case 'example':
    case 'question':
    case 'rocket':
    case 'swords':
    case 'gem':
    case 'pencil':
    case 'tip':
    case 'star':
    case 'wip':
    // return 'rgba(159, 0, 90, 0.9)';
    // return theme.palette.primary.main;
    // return 'rgba(135, 14, 222, 0.6)';
    // return theme.palette.secondary.main;
    // return theme.palette.success.main;
    // return theme.palette.warning.main;
    // return 'rgba(255, 202, 45, 0.88)';
    // return 'rgba(255, 149, 0, 0.76)';
    default:
      return theme.palette.background.paper;
  }
};

