const getCalloutStyles = (type: string, theme: Theme): SxProps => ({
  backgroundColor: getBackgroundColorForCallout(type, theme),
  color: `${getCalloutTextColor(type, theme)} !important`,
  // padding: '2rem',
  // paddingTop: '0',
  // paddingBottom: '3rem',
  border: 'none',
  // borderTopLeftRadius: '1rem',
  // borderBottomRightRadius: '1rem',
  margin: 0,
  padding: '1rem',
  // marginTop: '1rem',
  // marginBottom: '1rem',
  span: {
    ['&:first-of-type']: {
      fontSize: '1.25rem',
      fontWeight: 700,
    },
    color: `${getCalloutTextColor(type, theme)} !important`,
    // margin: 0,
    // padding: 0,
    // paddingTop: '2rem',
  },
});

export const Callout = ({ children, title, type }: CalloutProps) => {
  const theme = useTheme();
  const titleRow =
    title ?
      <StyledTitleRow>
        {getIconForCallout(type)}
        {title}
      </StyledTitleRow>
    : undefined;

  return (
    <StyledBlockquote data-title={title} data-callout={type} sx={type ? getCalloutStyles(type, theme) : undefined}>
      {titleRow}
      {children}
    </StyledBlockquote>
  );
};
